ListNode* mergeLists(ListNode* l1, ListNode* l2) {
    ListNode dummy;
    dummy.next = NULL;
    ListNode* node = &dummy;

    while (l1 && l2) {
        if (l1->val > l2->val) {
            node->next = l2;
            l2 = l2->next;
        } else {
            node->next = l1;
            l1 = l1->next;
        }
        node = node->next;
    }

    node->next = (l1 ? l1 : l2);
    return dummy.next;
}

ListNode* mergeKLists(ListNode** lists, int k) {
    if (k == 0) return NULL;

    while (k > 1) {
        int new_k = 0;

        for (int i = 0; i < k; i += 2) {
            ListNode* l1 = lists[i];
            ListNode* l2 = (i + 1 < k) ? lists[i + 1] : NULL;
            lists[new_k++] = mergeLists(l1, l2);
        }

        k = new_k;
    }

    return lists[0];
}

