class MinHeap {
    constructor() {
        this.data = [];
    }

    size() {
        return this.data.length;
    }

    push(node) {
        this.data.push(node);
        this._siftUp(this.data.length - 1);
    }

    pop() {
        if (this.size() === 0) return null;
        if (this.size() === 1) return this.data.pop();

        const root = this.data[0];
        this.data[0] = this.data.pop();
        this._siftDown(0);
        return root;
    }

    _siftUp(i) {
        while (i > 0) {
            const p = Math.floor((i - 1) / 2);
            if (this.data[p].val <= this.data[i].val) break;
            [this.data[p], this.data[i]] = [this.data[i], this.data[p]];
            i = p;
        }
    }

    _siftDown(i) {
        const n = this.size();
        while (true) {
            let smallest = i;
            const l = 2 * i + 1;
            const r = 2 * i + 2;

            if (l < n && this.data[l].val < this.data[smallest].val) {
                smallest = l;
            }
            if (r < n && this.data[r].val < this.data[smallest].val) {
                smallest = r;
            }

            if (smallest === i) break;
            [this.data[i], this.data[smallest]] = [this.data[smallest], this.data[i]];
            i = smallest;
        }
    }
}

class Solution {
    mergeKLists(lists) {
        if (!lists || lists.length === 0) return null;

        const heap = new MinHeap();

        // Push initial heads
        for (const node of lists) {
            if (node !== null) {
                heap.push(node);
            }
        }

        const dummy = new ListNode(0);
        let tail = dummy;

        while (heap.size() > 0) {
            const node = heap.pop();

            tail.next = node;
            tail = node;

            if (node.next !== null) {
                heap.push(node.next);
            }
        }

        return dummy.next;
    }
}
